document.addEventListener('DOMContentLoaded', () => {
  const toggle = document.querySelector('.skt-work__toggle');
  const more = document.getElementById('skt-work-more');
  if (!toggle || !more) return;

  toggle.addEventListener('click', (e) => {
    e.preventDefault();
    e.stopPropagation();

    // 1) guarda on és el toggle a la pantalla (viewport)
    const topBefore = toggle.getBoundingClientRect().top;

    // 2) toggle state
    const isExpanded = toggle.getAttribute('aria-expanded') === 'true';
    toggle.setAttribute('aria-expanded', String(!isExpanded));
    more.hidden = isExpanded;

    const span = toggle.querySelector('span');
    if (span) span.textContent = isExpanded ? 'Saber-ne més' : 'Reduir';

    // 3) després del reflow, compensa el salt
    requestAnimationFrame(() => {
      const topAfter = toggle.getBoundingClientRect().top;
      window.scrollBy(0, topAfter - topBefore);
      toggle.blur(); // opcional: evita “focus scroll” en alguns casos
    });
  });
});
